-- ----------------------------
-- Table structure for pendaftaran
-- ----------------------------
DROP TABLE IF EXISTS `pendaftaran`;
CREATE TABLE `pendaftaran` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTO_INCREMENT,
  `tgl_pendaftaran` TEXT NOT NULL,
  `id_pasien` TEXT NOT NULL,
  `status_pendaftaran` TEXT NOT NULL,
  `status_periksa` TEXT NOT NULL DEFAULT `belum`,
  `cara_bayar` TEXT NOT NULL,
  `id_user` TEXT NOT NULL,
  `no_antrian` TEXT NOT NULL DEFAULT `0`,
  `status_bayar` TEXT NOT NULL DEFAULT `belum`
);

-- ----------------------------
-- Records of pendaftaran
-- ----------------------------

-- ----------------------------
-- Table structure for pendidikan
-- ----------------------------
DROP TABLE IF EXISTS `pendidikan`;
CREATE TABLE `pendidikan` (
  `tingkat` TEXT NOT NULL,
  `indek` tinyint NOT NULL,
  `gapok1` REAL NOT NULL,
  `kenaikan` REAL NOT NULL,
  `maksimal` int NOT NULL,
  PRIMARY KEY (`tingkat`)
);

-- ----------------------------
-- Records of pendidikan
-- ----------------------------

-- ----------------------------
-- Table structure for penjamin
-- ----------------------------
DROP TABLE IF EXISTS `penjamin`;
CREATE TABLE `penjamin` (
  `id` INTEGER NOT NULL,
  `nama_penjamin` TEXT NOT NULL,
  PRIMARY KEY (`id`)
);

-- ----------------------------
-- Records of penjamin
-- ----------------------------

-- ----------------------------
-- Table structure for perusahaan_pasien
-- ----------------------------
DROP TABLE IF EXISTS `perusahaan_pasien`;
CREATE TABLE `perusahaan_pasien` (
  `kode_perusahaan` TEXT NOT NULL,
  `nama_perusahaan` TEXT DEFAULT NULL,
  `alamat` TEXT DEFAULT NULL,
  `kota` TEXT DEFAULT NULL,
  `no_telp` TEXT DEFAULT NULL,
  PRIMARY KEY (`kode_perusahaan`)
);

-- ----------------------------
-- Records of perusahaan_pasien
-- ----------------------------

-- ----------------------------
-- Table structure for prosedur_pasien
-- ----------------------------
DROP TABLE IF EXISTS `prosedur_pasien`;
CREATE TABLE `prosedur_pasien` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTO_INCREMENT,
  `id_pendaftaran` TEXT NOT NULL,
  `kode_prosedur` TEXT NOT NULL,
  `nama_prosedur` TEXT NOT NULL,
  `keterangan` TEXT NOT NULL,
  `id_user` TEXT NOT NULL,
  `tgl_input` TEXT NOT NULL
);

-- ----------------------------
-- Records of prosedur_pasien
-- ----------------------------

-- ----------------------------
-- Table structure for remember_me
-- ----------------------------
DROP TABLE IF EXISTS `remember_me`;
CREATE TABLE `remember_me` (
  `id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT,
  `token` text NOT NULL,
  `user_id` integer NOT NULL,
  `expiry` integer NOT NULL,
  FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE NO ACTION
);

-- ----------------------------
-- Records of remember_me
-- ----------------------------

-- ----------------------------
-- Table structure for resiko_kerja
-- ----------------------------
DROP TABLE IF EXISTS `resiko_kerja`;
CREATE TABLE `resiko_kerja` (
  `kode_resiko` TEXT NOT NULL,
  `nama_resiko` TEXT DEFAULT NULL,
  `indek` tinyint DEFAULT NULL,
  PRIMARY KEY (`kode_resiko`)
);

-- ----------------------------
-- Records of resiko_kerja
-- ----------------------------

