  `nm_ruang_ok` TEXT DEFAULT NULL,
  PRIMARY KEY (`kd_ruang_ok`)
);

-- ----------------------------
-- Records of ruang_ok
-- ----------------------------

-- ----------------------------
-- Table structure for satu_sehat
