  `id_observation_ttvnadi` TEXT DEFAULT NULL,
  `id_observation_ttvrespirasi` TEXT DEFAULT NULL,
  `id_observation_ttvsuhu` TEXT DEFAULT NULL,
  `id_observation_ttvspo2` TEXT DEFAULT NULL,
  `id_observation_ttvgcs` TEXT DEFAULT NULL,
  `id_observation_ttvtinggi` TEXT DEFAULT NULL,
  `id_observation_ttvberat` TEXT DEFAULT NULL,
  `id_observation_ttvperut` TEXT DEFAULT NULL,
  `id_observation_ttvtensi` TEXT DEFAULT NULL,
  `id_observation_ttvkesadaran` TEXT DEFAULT NULL
);

